// ═══════════════════════════════════════════════════
// NOIZY Health Dashboard v2 — Comprehensive System Check
// Checks ALL services in the NOIZY empire
// ═══════════════════════════════════════════════════

const checks = [
  // Local Docker services
  { name: 'n8n',             url: 'http://localhost:5678/healthz',                 type: 'docker',   critical: true  },
  { name: 'PostgreSQL',      url: 'http://localhost:5432',                         type: 'docker',   critical: true,  tcpCheck: true },
  { name: 'Redis',           url: 'http://localhost:6379',                         type: 'docker',   critical: true,  tcpCheck: true },
  { name: 'Open WebUI',      url: 'http://localhost:3080/',                        type: 'docker',   critical: false },
  { name: 'RabbitMQ',        url: 'http://localhost:15672/',                       type: 'docker',   critical: false },
  { name: 'Qdrant',          url: 'http://localhost:6333/collections',             type: 'docker',   critical: false },
  { name: 'Grafana',         url: 'http://localhost:3000/api/health',              type: 'docker',   critical: false },
  { name: 'Neo4j',           url: 'http://localhost:7474/',                        type: 'docker',   critical: false },

  // Cloudflare Workers
  { name: 'Heaven',        url: 'https://noizy.ai/api/status',                  type: 'cf-worker', critical: true  },
  { name: 'Consent Gateway', url: 'https://consent.noizy.ai/health',              type: 'cf-worker', critical: true  },
  { name: 'Webhook Proxy',   url: 'https://webhook-proxy.rsp-5f3.workers.dev/stats', type: 'cf-worker', critical: false },

  // External APIs
  { name: 'Linear API',      url: 'https://api.linear.app/graphql',               type: 'external',  critical: false, method: 'POST', body: '{"query":"{ viewer { id } }"}', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + ($env.LINEAR_API_KEY || 'test') } },
  { name: 'Notion API',      url: 'https://api.notion.com/v1/users/me',           type: 'external',  critical: false, headers: { 'Authorization': 'Bearer ' + ($env.NOTION_API_KEY || 'test'), 'Notion-Version': '2022-06-28' } },
  { name: 'GitHub API',      url: 'https://api.github.com/rate_limit',            type: 'external',  critical: false, headers: { 'Authorization': 'token ' + ($env.GITHUB_TOKEN || 'test') } },
];

return [{ json: { checks, timestamp: new Date().toISOString() } }];

// Execute all health checks with timeouts
const { checks, timestamp } = $input.first().json;

const results = [];

for (const check of checks) {
  const start = Date.now();
  let status = 'unknown';
  let responseTime = 0;
  let statusCode = 0;
  let error = null;

  if (check.tcpCheck) {
    // TCP-only services (Postgres, Redis) - just mark as needing Docker check
    status = 'check-via-docker';
    responseTime = 0;
  } else {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 8000);

      const opts = {
        method: check.method || 'GET',
        signal: controller.signal,
        headers: check.headers || {},
      };
      if (check.body) opts.body = check.body;

      const response = await fetch(check.url, opts);
      clearTimeout(timeout);

      statusCode = response.status;
      responseTime = Date.now() - start;

      if (statusCode >= 200 && statusCode < 400) {
        status = 'healthy';
      } else if (statusCode >= 400 && statusCode < 500) {
        status = 'degraded';
      } else {
        status = 'unhealthy';
      }
    } catch (err) {
      responseTime = Date.now() - start;
      error = err.message || 'Connection failed';

      if (error.includes('abort') || error.includes('timeout')) {
        status = 'timeout';
      } else if (error.includes('ECONNREFUSED') || error.includes('fetch failed')) {
        status = 'down';
      } else {
        status = 'error';
      }
    }
  }

  results.push({
    name: check.name,
    type: check.type,
    critical: check.critical,
    status,
    statusCode,
    responseTime,
    error,
    url: check.url,
  });
}

// Calculate overall health
const healthy = results.filter(r => r.status === 'healthy').length;
const criticalDown = results.filter(r => r.critical && ['down', 'error', 'timeout', 'unhealthy'].includes(r.status));
const total = results.length;
const tcpSkipped = results.filter(r => r.status === 'check-via-docker').length;

const overallStatus = criticalDown.length > 0 ? '🔴 CRITICAL' : (healthy + tcpSkipped >= total * 0.7 ? '🟢 HEALTHY' : '🟡 DEGRADED');

return [{ json: {
  overallStatus,
  timestamp,
  summary: {
    total,
    healthy,
    degraded: results.filter(r => r.status === 'degraded').length,
    down: results.filter(r => ['down', 'error', 'timeout', 'unhealthy'].includes(r.status)).length,
    tcpSkipped,
    criticalIssues: criticalDown.map(r => r.name),
  },
  results,
  statusMatrix: results.map(r => ({
    service: r.name,
    icon: r.status === 'healthy' ? '✅' : r.status === 'degraded' ? '⚠️' : r.status === 'check-via-docker' ? '🔵' : '❌',
    status: r.status,
    ms: r.responseTime,
    type: r.type,
  }))
} }];

