={
  "parent": { "database_id": "{{ $env.NOTION_HEALTH_DB_ID || $env.NOTION_EVENTS_DB_ID }}" },
  "properties": {
    "Status": { "title": [{ "text": { "content": $json.overallStatus + " — Empire Health Report" } }] },
    "Summary": { "rich_text": [{ "text": { "content": `${$json.summary.healthy}/${$json.summary.total} healthy | ${$json.summary.down} down | Critical: ${$json.summary.criticalIssues.join(', ') || 'none'}` } }] },
    "Matrix": { "rich_text": [{ "text": { "content": $json.statusMatrix.map(s => `${s.icon} ${s.service} (${s.ms}ms)`).join('\n').substring(0, 2000) } }] },
    "Timestamp": { "date": { "start": $json.timestamp } }
  }
}
